"use client";

import React from 'react';
import { motion } from 'framer-motion';

const projects = [
  {
    name: 'Rahi.AI',
    description: 'An AI-powered platform for real-time insights',
    link: 'https://rahi.ai',
  },
  {
    name: 'Sarthisync-live',
    description: 'A live synchronization service for data and applications',
    link: 'https://sarthisync.live',
  },
  {
    name: 'Smart Document Workspace',
    description: 'A collaborative environment for document management',
    link: 'https://smartdocuments.com',
  },
];

const ProjectCard = ({ project }) => (
  <motion.div 
    initial={{ opacity: 0, y: 20 }} 
    animate={{ opacity: 1, y: 0 }}
    transition={{ duration: 0.5 }}
    style={{ border: '1px solid #ccc', padding: '16px', margin: '8px', borderRadius: '8px' }}
  >
    <h3>{project.name}</h3>
    <p>{project.description}</p>
    <a href={project.link} target="_blank" rel="noopener noreferrer">View Project</a>
  </motion.div>
);

const Projects = () => (
  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
    <h2>Projects</h2>
    <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'center' }}>
      {projects.map((project) => (
        <ProjectCard key={project.name} project={project} />
      ))}
    </div>
  </div>
);

export default Projects;